#include<bits/stdc++.h>
#define ll long long
using namespace std;
const int MAXN=1e5+5;
int h[MAXN],n,f[MAXN];
stack<int> st;
int main(void){
	scanf("%d",&n);
	for(int i=1;i<=n;++i)scanf("%d",h+i);
	for(int i=n;i>=1;--i){
		while(st.size()&&h[st.top()]<=h[i])st.pop();
		f[i]=((st.size())?(st.top()):(0)),st.push(i);
	}for(int i=1;i<=n;++i)printf("%d\n",f[i]);
	return false;
}
